/**
 * EncounterDialog — FTL-style encounter dialog panel.
 * Displays encounter narrative text, options with requirements,
 * result text, and handles keyboard + gamepad navigation.
 *
 * Extends UIPanel for focus management and base panel behavior.
 *
 * @module EncounterDialog
 */

import { UIPanel } from './UIPanel.js';
import DebugLog from '../debug/DebugLog.js';

// ─── Attribute abbreviation labels ───────────────────────────────────────────

const ATTR_LABELS = {
  might:       'Might',
  agility:     'Agility',
  wit:         'Wit',
  presence:    'Presence',
  endurance:   'Endurance',
  attunement:  'Attunement',
};

// ─── Encounter type display config ───────────────────────────────────────────

const TYPE_CONFIG = {
  dialog:    { label: 'Encounter',   color: '#c8a020' },
  combat:    { label: 'Ambush',      color: '#c83020' },
  merchant:  { label: 'Traveler',    color: '#4a9a4a' },
  shrine:    { label: 'Shrine',      color: '#7a5aba' },
  discovery: { label: 'Discovery',   color: '#2a8aaa' },
  rest:      { label: 'Rest Site',   color: '#4a7a4a' },
  trap:      { label: 'Danger',      color: '#c83020' },
  default:   { label: 'Encounter',   color: '#c8a020' },
};

// ─── EncounterDialog ──────────────────────────────────────────────────────────

class EncounterDialog extends UIPanel {
  constructor() {
    super('panel-encounter-dialog', {
      trapFocus: true,
      zLayer: 'modal',
    });

    /** @type {object|null} Active encounter data */
    this._encounter = null;

    /** @type {object[]|null} Party characters for condition checks */
    this._partyChars = null;

    /** @type {Function|null} Called with result when encounter resolves */
    this._onComplete = null;

    /** @type {boolean} Whether we're in the result phase (after picking an option) */
    this._inResultPhase = false;

    /** @type {number|null} Index of the chosen option */
    this._chosenIndex = null;

    // Keyboard shortcut handler (1-4 keys, Enter, Escape)
    this._keyHandler = (e) => this._onKeydown(e);
  }

  // ─── Public API ─────────────────────────────────────────────────────────────

  /**
   * Display an encounter dialog.
   * @param {object} encounter — Encounter data object from EncounterSystem
   * @param {object[]} partyChars — Array of party character objects
   * @param {Function} onComplete — Called with the resolution result when done
   */
  show(encounter, partyChars, onComplete) {
    this._encounter    = encounter;
    this._partyChars   = partyChars ?? [];
    this._onComplete   = onComplete ?? null;
    this._inResultPhase = false;
    this._chosenIndex  = null;

    this._renderEncounter();
    this._addDarkOverlay();
    window.addEventListener('keydown', this._keyHandler);

    super.show();

    // Focus the first option button after rendering
    this._focusFirstOption();

    DebugLog.event(
      `[encounter] Dialog shown; id=${encounter?.id ?? 'unknown'} ` +
      `title="${encounter?.title ?? ''}" options=${encounter?.options?.length ?? 0}`
    );
  }

  /**
   * Hide the dialog and clean up.
   */
  hide() {
    window.removeEventListener('keydown', this._keyHandler);
    this._removeDarkOverlay();
    super.hide();
    this._encounter   = null;
    this._partyChars  = null;
    this._onComplete  = null;
  }

  // ─── Rendering ──────────────────────────────────────────────────────────────

  _renderEncounter() {
    const enc = this._encounter;
    if (!enc) return;

    const typeCfg = TYPE_CONFIG[enc.type] ?? TYPE_CONFIG.default;
    const options = enc.options ?? [];

    const optionsHTML = options
      .map((opt, i) => this._renderOption(opt, i))
      .join('');

    this.el.innerHTML = `
      <div class="enc-dialog-inner">

        <!-- Header -->
        <div class="enc-header">
          <div class="enc-type-badge" style="color:${typeCfg.color};">${typeCfg.label}</div>
          <div class="enc-title">${this._escHtml(enc.title ?? 'Unknown Encounter')}</div>
        </div>

        <!-- Narrative text -->
        <div class="enc-body">
          <p class="enc-narrative">${this._escHtml(enc.description ?? '')}</p>
        </div>

        <!-- Options list -->
        <div class="enc-options" id="enc-options-list" role="group" aria-label="Choose an action">
          ${optionsHTML}
        </div>

        <!-- Keyboard hint -->
        <div class="enc-hint">
          Press <kbd>1</kbd>–<kbd>${Math.min(options.length, 9)}</kbd> to choose &nbsp;&middot;&nbsp;
          <kbd>Esc</kbd> to pass
        </div>

      </div>
    `;

    this._applyDialogStyles();
    this._attachOptionHandlers();
  }

  _renderOption(opt, index) {
    const { met, requirementHTML } = this._checkRequirements(opt);
    const lockedClass  = met ? '' : 'enc-option--locked';
    const opacityStyle = met ? '' : 'opacity:0.5;';
    const numLabel     = `[${index + 1}]`;

    // Show skill/attribute roll result hint if it's a check
    let rollHintHTML = '';
    if (opt.check) {
      const dc = opt.check.dc ?? '?';
      const attr = ATTR_LABELS[opt.check.attribute] ?? opt.check.attribute ?? 'Skill';
      rollHintHTML = `
        <span class="enc-option-roll-hint">${attr} check — DC ${dc}</span>
      `;
    }

    return `
      <button
        class="enc-option ${lockedClass}"
        data-option-index="${index}"
        style="${opacityStyle}"
        ${met ? '' : 'aria-disabled="true"'}
        tabindex="${met ? '0' : '-1'}"
        aria-label="Option ${index + 1}: ${this._escHtml(opt.text ?? '')}"
      >
        <span class="enc-option-num">${numLabel}</span>
        <span class="enc-option-content">
          <span class="enc-option-text">${this._escHtml(opt.text ?? '')}</span>
          ${requirementHTML}
          ${rollHintHTML}
        </span>
      </button>
    `;
  }

  /**
   * Evaluate option conditions against the party.
   * @param {object} opt
   * @returns {{ met: boolean, requirementHTML: string }}
   */
  _checkRequirements(opt) {
    if (!opt.requires) return { met: true, requirementHTML: '' };

    const reqs = Array.isArray(opt.requires) ? opt.requires : [opt.requires];
    const tags = [];
    let allMet = true;

    for (const req of reqs) {
      if (req.gold != null) {
        const hasGold = this._partyHasGold(req.gold);
        tags.push({
          label: `${req.gold} gold`,
          met: hasGold,
        });
        if (!hasGold) allMet = false;
      } else if (req.attribute) {
        const attr = req.attribute;
        const minVal = req.value ?? 10;
        const hasStat = this._partyHasStat(attr, minVal);
        const attrLabel = ATTR_LABELS[attr] ?? attr;
        tags.push({
          label: `${attrLabel} ${minVal}+`,
          met: hasStat,
        });
        if (!hasStat) allMet = false;
      } else if (req.item) {
        const hasItem = this._partyHasItem(req.item);
        tags.push({
          label: req.item,
          met: hasItem,
        });
        if (!hasItem) allMet = false;
      } else if (req.tag) {
        // Scenario tool or skill tag — treat as unverifiable (met=true for display)
        tags.push({
          label: req.tag,
          met: true,
        });
      }
    }

    const reqHTML = tags.map(t => `
      <span class="enc-req-tag ${t.met ? 'enc-req-tag--met' : 'enc-req-tag--fail'}">
        ${this._escHtml(t.label)}
      </span>
    `).join('');

    return {
      met: allMet,
      requirementHTML: tags.length > 0
        ? `<span class="enc-option-reqs">${reqHTML}</span>`
        : '',
    };
  }

  // ─── Result phase ────────────────────────────────────────────────────────────

  _renderResult(result) {
    this._inResultPhase = true;

    const enc = this._encounter;
    const chosenOpt = enc?.options?.[this._chosenIndex];
    const rollText = result?.roll != null
      ? `<div class="enc-roll-result">
           Roll: <span class="enc-roll-num">${result.roll}</span>
           ${result.success != null
             ? `&nbsp;— <span class="${result.success ? 'enc-roll-success' : 'enc-roll-fail'}">
                  ${result.success ? 'Success' : 'Failure'}
                </span>`
             : ''}
         </div>`
      : '';

    const outcomeClass = result?.success === false ? 'enc-outcome--fail' : 'enc-outcome--success';

    this.el.innerHTML = `
      <div class="enc-dialog-inner">

        <!-- Header (kept for context) -->
        <div class="enc-header">
          <div class="enc-type-badge" style="color:#888;">Result</div>
          <div class="enc-title">${this._escHtml(enc?.title ?? 'Encounter')}</div>
        </div>

        <!-- Chosen option recap -->
        ${chosenOpt ? `
          <div class="enc-chosen-recap">
            You chose: <em>${this._escHtml(chosenOpt.text ?? '')}</em>
          </div>
        ` : ''}

        <!-- Roll result (if applicable) -->
        ${rollText}

        <!-- Outcome narrative -->
        <div class="enc-body ${outcomeClass}">
          <p class="enc-narrative">${this._escHtml(result?.text ?? result?.description ?? 'The encounter concludes.')}</p>
        </div>

        <!-- Continue button -->
        <div class="enc-continue-row">
          <button id="enc-btn-continue" class="spellroads-btn spellroads-btn--primary enc-continue-btn"
            tabindex="0" aria-label="Continue">
            Continue
          </button>
        </div>

        <!-- Keyboard hint -->
        <div class="enc-hint">
          Press <kbd>Enter</kbd> or <kbd>Esc</kbd> to continue
        </div>

      </div>
    `;

    this._applyDialogStyles();

    const continueBtn = document.getElementById('enc-btn-continue');
    if (continueBtn) {
      continueBtn.addEventListener('click', () => this._finish(result));
      continueBtn.focus();
    }

    DebugLog.event(
      `[encounter] Result shown; option=${this._chosenIndex} ` +
      `roll=${result?.roll ?? 'n/a'} success=${result?.success ?? 'n/a'}`
    );
  }

  // ─── Option selection ────────────────────────────────────────────────────────

  _selectOption(index) {
    const enc = this._encounter;
    if (!enc || this._inResultPhase) return;

    const options = enc.options ?? [];
    if (index < 0 || index >= options.length) return;

    const opt = options[index];

    // Check if the option's requirements are met — locked options skip
    const { met } = this._checkRequirements(opt);
    if (!met) {
      DebugLog.info(`[encounter] Option ${index} locked — requirements not met`);
      this._shakeOption(index);
      return;
    }

    this._chosenIndex = index;

    // Animate the selection briefly, then resolve
    const optionEls = this.el.querySelectorAll('.enc-option');
    if (optionEls[index]) {
      optionEls[index].classList.add('enc-option--selected');
    }

    // Resolve via EncounterSystem if available, otherwise create a stub result
    const result = this._resolveOption(enc, index);

    // Short delay so the selection flash is visible
    setTimeout(() => this._renderResult(result), 180);
  }

  _resolveOption(encounter, optionIndex) {
    // Call EncounterSystem.resolveOption if it exists
    try {
      // Dynamic import would be circular; use global or injected reference
      if (window.__encounterSystem?.resolveOption) {
        return window.__encounterSystem.resolveOption(encounter, optionIndex, this._partyChars);
      }
    } catch (e) {
      DebugLog.warn(`[encounter] EncounterSystem.resolveOption failed: ${e.message}`);
    }

    // Fallback: use outcome data embedded in the option
    const opt = encounter?.options?.[optionIndex];
    const outcomes = opt?.outcomes ?? opt?.outcome;

    if (Array.isArray(outcomes) && outcomes.length > 0) {
      // Pick a weighted or random outcome
      return outcomes[Math.floor(Math.random() * outcomes.length)];
    }

    if (outcomes && typeof outcomes === 'object') {
      return outcomes;
    }

    // Last resort stub
    return {
      text: opt?.resultText ?? 'The encounter resolves without incident.',
      success: true,
    };
  }

  _finish(result) {
    const cb = this._onComplete;
    this.hide();
    if (cb) cb(result);
  }

  // ─── Keyboard handling ───────────────────────────────────────────────────────

  _onKeydown(e) {
    if (!this._visible) return;

    if (this._inResultPhase) {
      if (e.key === 'Enter' || e.key === 'Escape') {
        e.preventDefault();
        this._finish(null);
      }
      return;
    }

    // 1-9 key: select that option
    const numMatch = e.key.match(/^([1-9])$/);
    if (numMatch) {
      e.preventDefault();
      this._selectOption(parseInt(numMatch[1], 10) - 1);
      return;
    }

    if (e.key === 'Escape') {
      e.preventDefault();
      // Escape = pass / skip — resolves with a pass result
      this._finish({ text: 'You pass by without engaging.', passed: true });
    }
  }

  // ─── DOM helpers ─────────────────────────────────────────────────────────────

  _attachOptionHandlers() {
    const optionBtns = this.el.querySelectorAll('.enc-option');
    optionBtns.forEach((btn) => {
      btn.addEventListener('click', () => {
        const idx = parseInt(btn.dataset.optionIndex, 10);
        this._selectOption(idx);
      });
    });
  }

  _focusFirstOption() {
    const firstEnabled = this.el.querySelector('.enc-option:not(.enc-option--locked)');
    if (firstEnabled) {
      firstEnabled.focus();
    }
  }

  _shakeOption(index) {
    const optionEls = this.el.querySelectorAll('.enc-option');
    const el = optionEls[index];
    if (!el) return;
    el.classList.add('enc-option--shake');
    setTimeout(() => el.classList.remove('enc-option--shake'), 400);
  }

  // ─── Dark overlay ────────────────────────────────────────────────────────────

  _addDarkOverlay() {
    let overlay = document.getElementById('enc-dark-overlay');
    if (!overlay) {
      overlay = document.createElement('div');
      overlay.id = 'enc-dark-overlay';
      overlay.style.cssText = `
        position: fixed;
        inset: 0;
        background: rgba(0, 0, 0, 0.65);
        z-index: 299;
        pointer-events: all;
      `;
      document.body.appendChild(overlay);
    }
    overlay.style.display = 'block';
  }

  _removeDarkOverlay() {
    const overlay = document.getElementById('enc-dark-overlay');
    if (overlay) overlay.style.display = 'none';
  }

  // ─── Requirement checks ───────────────────────────────────────────────────────

  _partyHasGold(amount) {
    try {
      const WorldState = window.__worldState;
      if (WorldState) return (WorldState.partyGold ?? 0) >= amount;
    } catch (_) {}
    return true; // optimistic default when WorldState unavailable
  }

  _partyHasStat(attribute, minValue) {
    if (!this._partyChars || this._partyChars.length === 0) return false;
    return this._partyChars.some(char => {
      const val = char?.attributes?.[attribute] ?? char?.stats?.[attribute] ?? 0;
      return val >= minValue;
    });
  }

  _partyHasItem(itemId) {
    if (!this._partyChars || this._partyChars.length === 0) return false;
    return this._partyChars.some(char => {
      const inv = char?.inventory ?? [];
      return inv.some(item => item.id === itemId || item.itemId === itemId);
    });
  }

  // ─── Utility ─────────────────────────────────────────────────────────────────

  _escHtml(str) {
    return String(str ?? '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  // ─── Inline styles ────────────────────────────────────────────────────────────
  // Applied once after rendering; uses CSS variables where possible

  _applyDialogStyles() {
    // Position the dialog centered
    Object.assign(this.el.style, {
      position:        'fixed',
      top:             '50%',
      left:            '50%',
      transform:       'translate(-50%, -50%)',
      width:           'min(600px, 92vw)',
      maxHeight:       '88vh',
      overflow:        'hidden',
      display:         'flex',
      flexDirection:   'column',
      zIndex:          '300',
      border:          '1px solid #7a5a20',
      borderRadius:    '6px',
      boxShadow:       '0 0 60px rgba(0,0,0,0.9), 0 0 20px rgba(180,130,0,0.15)',
      background:      'transparent',
      pointerEvents:   'all',
    });

    // Inject component CSS once
    if (!document.getElementById('enc-dialog-styles')) {
      const style = document.createElement('style');
      style.id = 'enc-dialog-styles';
      style.textContent = ENC_STYLES;
      document.head.appendChild(style);
    }
  }
}

// ─── Component CSS ────────────────────────────────────────────────────────────

const ENC_STYLES = `
/* ── Encounter Dialog ───────────────────────────────────────────────────── */

#panel-encounter-dialog {
  font-family: 'Georgia', 'Times New Roman', serif;
}

#panel-encounter-dialog.visible {
  display: flex !important;
}

.enc-dialog-inner {
  display: flex;
  flex-direction: column;
  background: #120e08;
  border-radius: 6px;
  overflow: hidden;
  width: 100%;
  max-height: 88vh;
}

/* Header */
.enc-header {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 12px 18px;
  background: #0c0908;
  border-bottom: 1px solid #5a4a20;
  flex-shrink: 0;
}

.enc-type-badge {
  font-size: 10px;
  font-weight: bold;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  padding: 3px 8px;
  border-radius: 3px;
  background: rgba(255,255,255,0.05);
  border: 1px solid currentColor;
  white-space: nowrap;
  flex-shrink: 0;
}

.enc-title {
  font-size: clamp(15px, 2vw, 18px);
  font-weight: bold;
  color: #e8d090;
  letter-spacing: 0.04em;
  line-height: 1.3;
}

/* Narrative body */
.enc-body {
  padding: 16px 18px;
  border-bottom: 1px solid #2a1e0a;
  flex-shrink: 0;
}

.enc-body.enc-outcome--fail {
  border-left: 3px solid #c83020;
}

.enc-body.enc-outcome--success {
  border-left: 3px solid #40a060;
}

.enc-narrative {
  font-size: clamp(13px, 1.5vw, 15px);
  color: #ccc0a0;
  line-height: 1.6;
  margin: 0;
}

/* Options */
.enc-options {
  display: flex;
  flex-direction: column;
  gap: 0;
  overflow-y: auto;
  flex: 1;
  min-height: 0;
  padding: 8px 0;
}

.enc-option {
  display: flex;
  align-items: flex-start;
  gap: 10px;
  padding: 12px 18px;
  min-height: 44px;
  background: transparent;
  border: none;
  border-left: 3px solid transparent;
  color: #d0c090;
  font-family: 'Georgia', 'Times New Roman', serif;
  font-size: clamp(13px, 1.4vw, 15px);
  text-align: left;
  cursor: pointer;
  transition: background 0.12s, border-color 0.12s, color 0.12s;
  width: 100%;
  line-height: 1.4;
}

.enc-option:hover,
.enc-option:focus-visible {
  background: rgba(200, 160, 32, 0.08);
  border-left-color: #c8a020;
  color: #f0d880;
  outline: none;
}

.enc-option:focus-visible {
  box-shadow: inset 0 0 0 1px #c8a02055;
}

.enc-option--locked {
  cursor: default;
  pointer-events: none;
}

.enc-option--selected {
  background: rgba(200, 160, 32, 0.18) !important;
  border-left-color: #e8c040 !important;
  color: #ffe87a !important;
}

@keyframes enc-shake {
  0%   { transform: translateX(0); }
  20%  { transform: translateX(-5px); }
  40%  { transform: translateX(5px); }
  60%  { transform: translateX(-4px); }
  80%  { transform: translateX(4px); }
  100% { transform: translateX(0); }
}

.enc-option--shake {
  animation: enc-shake 0.35s ease-in-out;
}

.enc-option-num {
  color: #7a6a3a;
  font-size: 12px;
  flex-shrink: 0;
  margin-top: 1px;
  min-width: 24px;
  font-weight: bold;
}

.enc-option-content {
  display: flex;
  flex-direction: column;
  gap: 3px;
  flex: 1;
}

.enc-option-text {
  display: block;
}

.enc-option-reqs {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  margin-top: 3px;
}

.enc-req-tag {
  font-size: 10px;
  padding: 2px 6px;
  border-radius: 2px;
  font-family: 'Courier New', monospace;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.enc-req-tag--met {
  background: rgba(64, 160, 96, 0.15);
  border: 1px solid #40a06060;
  color: #70c880;
}

.enc-req-tag--fail {
  background: rgba(200, 48, 32, 0.12);
  border: 1px solid #c8302060;
  color: #e06050;
}

.enc-option-roll-hint {
  font-size: 10px;
  color: #7a8aa8;
  font-style: italic;
  margin-top: 2px;
}

/* Chosen recap in result phase */
.enc-chosen-recap {
  padding: 8px 18px;
  font-size: 12px;
  color: #7a6a4a;
  font-style: italic;
  border-bottom: 1px solid #1e1508;
  flex-shrink: 0;
}

/* Roll result */
.enc-roll-result {
  padding: 8px 18px;
  font-size: 13px;
  color: #aaa8a0;
  background: rgba(255,255,255,0.02);
  border-bottom: 1px solid #1e1508;
  flex-shrink: 0;
  font-family: 'Courier New', monospace;
}

.enc-roll-num {
  font-size: 16px;
  font-weight: bold;
  color: #e8d080;
}

.enc-roll-success {
  color: #60c870;
  font-weight: bold;
}

.enc-roll-fail {
  color: #e05840;
  font-weight: bold;
}

/* Continue button */
.enc-continue-row {
  padding: 14px 18px 10px;
  border-top: 1px solid #2a1e0a;
  display: flex;
  justify-content: flex-end;
  flex-shrink: 0;
}

.enc-continue-btn {
  min-width: 120px;
}

/* Keyboard hint */
.enc-hint {
  padding: 6px 18px 12px;
  font-size: 10px;
  color: #504030;
  text-align: right;
  flex-shrink: 0;
}

.enc-hint kbd {
  font-size: 9px;
  padding: 1px 4px;
  background: #1a1410;
  border: 1px solid #4a3a1a;
  border-radius: 2px;
  font-family: 'Courier New', monospace;
  color: #7a6a4a;
}

/* Scrollbar inside options list */
.enc-options::-webkit-scrollbar {
  width: 4px;
}
.enc-options::-webkit-scrollbar-track {
  background: transparent;
}
.enc-options::-webkit-scrollbar-thumb {
  background: #3a2a10;
  border-radius: 2px;
}

/* ── Responsive ─────────────────────────────────────────────────────────── */
@media (max-width: 767px) {
  .enc-header { padding: 10px 14px; gap: 8px; }
  .enc-body   { padding: 12px 14px; }
  .enc-option { padding: 10px 14px; font-size: 13px; }
  .enc-hint   { padding: 5px 14px 10px; }
  .enc-continue-row { padding: 10px 14px; }
  .enc-title  { font-size: 15px; }
}
`;

// ─── Singleton export ─────────────────────────────────────────────────────────

export default new EncounterDialog();
