/**
 * LocalMapScene — Traversable tile-based local area.
 * Party movement, fog of war, minimap, and connection to RegionMap.
 *
 * @module LocalMapScene
 */

import { Graphics, Container, Text, TextStyle } from 'pixi.js';
import SceneManager from '../core/SceneManager.js';
import EventBus from '../core/EventBus.js';
import DebugLog from '../debug/DebugLog.js';
import WorldState from '../world/WorldState.js';
import InputManager from '../input/InputManager.js';
import { seedNoise, normalizedNoise2D } from '../utils/Noise.js';
import { createRNG } from '../utils/RNG.js';
import HUDPanel from '../ui/HUDPanel.js';
import EncounterDialog from '../ui/EncounterDialog.js';

// ─── Constants ────────────────────────────────────────────────────────────────

const TILE_SIZE = 32;
const LOCAL_MAP_W = 40;
const LOCAL_MAP_H = 30;
const MOVE_SPEED = 3; // tiles per second
const FOG_REVEAL_RADIUS = 8;

const MINIMAP_W = 160;
const MINIMAP_H = 120;
const MINIMAP_MARGIN = 12;

// ─── Biome → tile type mapping ────────────────────────────────────────────────

const BIOME_TILE_MAP = {
  ocean:       'water',
  frozen_sea:  'water',
  tundra:      'snow',
  taiga:       'forest',
  forest:      'forest',
  plains:      'grass',
  desert:      'sand',
  jungle:      'forest',
  mountain:    'mountain',
  volcanic:    'mountain',
  archipelago: 'sand',
};

const TILE_COLORS = {
  grass:    0x4a7a2a,
  forest:   0x2a5a1a,
  mountain: 0x7a6a5a,
  water:    0x1a3a5c,
  sand:     0xc8aa5a,
  snow:     0xe8e8f0,
  road:     0x8a7a5a,
};

// Slight variation per tile for organic look
const TILE_VARIATION = {
  grass:    0x0a1400,
  forest:   0x08100a,
  mountain: 0x100c08,
  water:    0x041020,
  sand:     0x181008,
  snow:     0x080808,
  road:     0x0c0808,
};

export default class LocalMapScene {
  async init({ renderer, regionId } = {}) {
    this._renderer = renderer;
    this._regionId = regionId ?? WorldState.currentRegionId ?? 0;
    this._panel = null;

    // PixiJS containers
    this._tileContainer = null;
    this._fogTileContainer = null;
    this._partyContainer = null;
    this._minimapContainer = null;
    this._minimapGfx = null;

    // Camera (follows party)
    this._camera = { x: 0, y: 0 };

    // Party position in tile coords (fractional for smooth movement)
    this._partyX = WorldState.partyPosition.x;
    this._partyY = WorldState.partyPosition.y;

    // Movement state
    this._moveAccum = { x: 0, y: 0 };

    // Ticker reference
    this._ticker = null;

    // Unsub functions
    this._resizeUnsub = null;
    this._fogUpdateUnsub = null;

    // Fog dirty flag
    this._fogDirty = true;

    // ── Encounter / time state ──────────────────────────────────────────────
    // Whether an encounter dialog is currently open (movement paused)
    this._encounterActive = false;

    // Accumulated travel distance since last encounter check (in tiles)
    this._distanceSinceCheck = 0;

    // Minimum tiles between encounter rolls (prevents back-to-back triggers)
    this._encounterCooldown = 0;

    // Previous tile coordinates — used to detect tile crossings
    this._prevTileX = null;
    this._prevTileY = null;

    window.__debug = window.__debug ?? {};
    window.__debug.currentScene = 'localMap';
    window.__debug.getLocalMap = () => ({
      regionId: this._regionId,
      gridW: LOCAL_MAP_W,
      gridH: LOCAL_MAP_H,
      partyX: Math.floor(this._partyX),
      partyY: Math.floor(this._partyY),
      tileCount: this._tiles ? this._tiles.length : 0,
    });

    if (!WorldState.world) {
      DebugLog.error('[world] LocalMapScene: no world data');
      SceneManager.transition('worldMap');
      return;
    }

    WorldState.currentRegionId = this._regionId;
    WorldState.currentLocalMapId = this._regionId;
    WorldState.exploreRegion(this._regionId);

    // Generate or retrieve local map
    this._tiles = this._getOrGenerateLocalMap();

    this._buildPixiTiles();
    this._buildPixiParty();
    this._buildMinimap();
    this._buildHTMLPanel();

    // Initial fog reveal (only when fog of war is enabled)
    if (window.__settings?.fogOfWar) {
      WorldState.revealAround(
        Math.floor(this._partyX),
        Math.floor(this._partyY),
        FOG_REVEAL_RADIUS
      );
    }
    this._fogDirty = true;

    // Set up ticker
    this._ticker = (ticker) => this._update(ticker.deltaMS);
    this._renderer.app.ticker.add(this._ticker);

    this._resizeUnsub = EventBus.on('renderer:resize', () => this._onResize());
    this._fogUpdateUnsub = EventBus.on('fog:update', () => { this._fogDirty = true; });

    // ── HUD overlay ─────────────────────────────────────────────────────────
    HUDPanel.init();

    this._showOnboardingHint();

    // ── Mobile d-pad ─────────────────────────────────────────────────────────
    this._buildMobileDpad();

    // Center camera on party immediately so the party token is visible on first frame
    this._updatePartyPosition();
    this._updateCamera();

    // Expose WorldState globally so SaveSystem can serialize/restore it
    window.__worldState = WorldState;

    DebugLog.info(`[world] LocalMapScene initialized; regionId=${this._regionId} tiles=${this._tiles.length}`);
  }

  // ─── Local map generation ────────────────────────────────────────────────────

  _getOrGenerateLocalMap() {
    const cached = WorldState.getLocalMap(this._regionId);
    if (cached) return cached.tiles;

    const region = WorldState.world.regions.find(r => r.id === this._regionId);
    const biome = region?.biome ?? 'plains';
    const baseTileType = BIOME_TILE_MAP[biome] ?? 'grass';

    // Seed noise specifically for this region's local map
    const localSeed = (WorldState.world.seed ^ (this._regionId * 0x5a3f7b11)) >>> 0;
    seedNoise(localSeed);
    const rng = createRNG(localSeed);

    const tiles = [];
    const noiseScale = 0.12;

    for (let y = 0; y < LOCAL_MAP_H; y++) {
      for (let x = 0; x < LOCAL_MAP_W; x++) {
        const noiseVal = normalizedNoise2D(x * noiseScale, y * noiseScale, 4, 0.5, 2.0);

        // Determine tile type based on biome + noise
        let tileType = baseTileType;

        if (baseTileType === 'grass') {
          if (noiseVal > 0.72) tileType = 'forest';
          else if (noiseVal < 0.18) tileType = 'water';
        } else if (baseTileType === 'forest') {
          if (noiseVal > 0.78) tileType = 'mountain';
          else if (noiseVal < 0.15) tileType = 'grass';
        } else if (baseTileType === 'mountain') {
          if (noiseVal < 0.25) tileType = 'grass';
          else if (noiseVal < 0.4) tileType = 'forest';
        } else if (baseTileType === 'snow') {
          if (noiseVal > 0.7) tileType = 'mountain';
        } else if (baseTileType === 'sand') {
          if (noiseVal < 0.15) tileType = 'water';
          else if (noiseVal > 0.80) tileType = 'grass';
        }

        // Add noise-based color variation
        const baseColor = TILE_COLORS[tileType] ?? 0x444444;
        const varColor = TILE_VARIATION[tileType] ?? 0x080808;

        // Apply slight hue variation using noise (±variation)
        const variationMask = rng.nextInt(0, 3);
        let finalColor = baseColor;
        if (variationMask === 0) {
          // Slightly lighter
          const vr = (varColor >> 16) & 0xff;
          const vg = (varColor >> 8) & 0xff;
          const vb = varColor & 0xff;
          const br = (baseColor >> 16) & 0xff;
          const bg = (baseColor >> 8) & 0xff;
          const bb = baseColor & 0xff;
          finalColor = (Math.min(255, br + vr) << 16) | (Math.min(255, bg + vg) << 8) | Math.min(255, bb + vb);
        } else if (variationMask === 1) {
          // Slightly darker
          const vr = (varColor >> 16) & 0xff;
          const vg = (varColor >> 8) & 0xff;
          const vb = varColor & 0xff;
          const br = (baseColor >> 16) & 0xff;
          const bg = (baseColor >> 8) & 0xff;
          const bb = baseColor & 0xff;
          finalColor = (Math.max(0, br - vr) << 16) | (Math.max(0, bg - vg) << 8) | Math.max(0, bb - vb);
        }

        tiles.push({ x, y, type: tileType, color: finalColor, passable: tileType !== 'water' && tileType !== 'mountain' });
      }
    }

    // Place road tiles along spellroads (if any pass through this region)
    this._addRoadTiles(tiles, region);

    WorldState.setLocalMap(this._regionId, { tiles, gridW: LOCAL_MAP_W, gridH: LOCAL_MAP_H });
    return tiles;
  }

  _addRoadTiles(tiles, region) {
    if (!region || !WorldState.world.spellroads) return;

    const world = WorldState.world;
    // Check which spellroad points are near this region's center
    const cx = region.centerX / world.gridW;
    const cy = region.centerY / world.gridH;

    for (const road of world.spellroads) {
      // Check if road comes near this region
      const nearPoint = road.find(p => {
        const dx = p.x - cx;
        const dy = p.y - cy;
        return Math.sqrt(dx * dx + dy * dy) < 0.15;
      });

      if (!nearPoint) continue;

      // Draw a road line through the center of the local map
      for (let i = 0; i < LOCAL_MAP_W; i++) {
        const ty = Math.floor(LOCAL_MAP_H / 2) + Math.round(Math.sin(i * 0.3) * 1.5);
        if (ty >= 0 && ty < LOCAL_MAP_H) {
          const tile = tiles[ty * LOCAL_MAP_W + i];
          if (tile && tile.type !== 'water') {
            tile.type = 'road';
            tile.color = TILE_COLORS.road;
            tile.passable = true;
          }
        }
      }
      break; // Only one road per local map
    }
  }

  // ─── PixiJS tile rendering ───────────────────────────────────────────────────

  _buildPixiTiles() {
    const worldLayer = this._renderer.layers.world;

    this._tileContainer = new Container();
    this._tileContainer.label = 'localTiles';
    worldLayer.addChild(this._tileContainer);

    // Draw all tiles as colored rectangles — batched by color (correct PixiJS v8 pattern).
    // Group tiles by color, draw all rects of the same color, then fill once.
    const byColor = new Map();
    for (const tile of this._tiles) {
      if (!byColor.has(tile.color)) byColor.set(tile.color, []);
      byColor.get(tile.color).push(tile);
    }

    for (const [color, group] of byColor) {
      const gfx = new Graphics();
      for (const tile of group) {
        gfx.rect(tile.x * TILE_SIZE, tile.y * TILE_SIZE, TILE_SIZE, TILE_SIZE);
      }
      gfx.fill({ color });
      this._tileContainer.addChild(gfx);
    }

    this._tileContainer.addChild(new Graphics()); // placeholder for compat

    // Fog container (drawn on top of tiles)
    this._fogTileContainer = new Container();
    this._fogTileContainer.label = 'localFog';
    worldLayer.addChild(this._fogTileContainer);
  }

  _rebuildFogTiles() {
    if (!this._fogTileContainer) return;

    // Skip fog rendering entirely when fog of war is disabled
    if (!window.__settings?.fogOfWar) {
      this._fogTileContainer.removeChildren();
      this._fogDirty = false;
      return;
    }

    this._fogTileContainer.removeChildren();

    // Batch fog by alpha level — PixiJS v8 requires grouping rects before calling fill()
    const fogOpaque = new Graphics(); // alpha 0.9 — completely unknown
    const fogPartial = new Graphics(); // alpha 0.4 — semi-explored

    for (let y = 0; y < LOCAL_MAP_H; y++) {
      for (let x = 0; x < LOCAL_MAP_W; x++) {
        const fogState = WorldState.getFogAt(this._regionId, x, y);
        if (fogState === 2) continue; // fully revealed — skip

        const px = x * TILE_SIZE;
        const py = y * TILE_SIZE;

        if (fogState === 0) {
          fogOpaque.rect(px, py, TILE_SIZE, TILE_SIZE);
        } else {
          fogPartial.rect(px, py, TILE_SIZE, TILE_SIZE);
        }
      }
    }

    fogOpaque.fill({ color: 0x000000, alpha: 0.9 });
    fogPartial.fill({ color: 0x000000, alpha: 0.4 });

    this._fogTileContainer.addChild(fogOpaque);
    this._fogTileContainer.addChild(fogPartial);
    this._fogDirty = false;
  }

  // ─── Party token ─────────────────────────────────────────────────────────────

  _buildPixiParty() {
    this._partyContainer = new Container();
    this._partyContainer.label = 'partyToken';
    this._renderer.layers.entities.addChild(this._partyContainer);

    this._partyGfx = new Graphics();
    this._partyContainer.addChild(this._partyGfx);

    this._drawPartyGfx();
  }

  _drawPartyGfx() {
    if (!this._partyGfx) return;
    this._partyGfx.clear();

    const cx = 0;
    const cy = 0;
    const r = 10;

    // Outer glow ring
    this._partyGfx.circle(cx, cy, r + 4);
    this._partyGfx.fill({ color: 0xffdd00, alpha: 0.2 });

    // Main circle
    this._partyGfx.circle(cx, cy, r);
    this._partyGfx.fill({ color: 0xffdd00 });
    this._partyGfx.circle(cx, cy, r);
    this._partyGfx.stroke({ color: 0xffffff, width: 2 });

    // Cross
    this._partyGfx.moveTo(cx - 6, cy);
    this._partyGfx.lineTo(cx + 6, cy);
    this._partyGfx.moveTo(cx, cy - 6);
    this._partyGfx.lineTo(cx, cy + 6);
    this._partyGfx.stroke({ color: 0xffffff, width: 1.5 });
  }

  _updatePartyPosition() {
    if (!this._partyContainer) return;

    const screenX = Math.floor(this._partyX) * TILE_SIZE + TILE_SIZE / 2;
    const screenY = Math.floor(this._partyY) * TILE_SIZE + TILE_SIZE / 2;

    this._partyContainer.x = screenX;
    this._partyContainer.y = screenY;
  }

  // ─── Camera ─────────────────────────────────────────────────────────────────

  _updateCamera() {
    const vw = this._renderer.width;
    const vh = this._renderer.height;

    const targetX = -(Math.floor(this._partyX) * TILE_SIZE + TILE_SIZE / 2 - vw / 2);
    const targetY = -(Math.floor(this._partyY) * TILE_SIZE + TILE_SIZE / 2 - vh / 2);

    // Clamp so map doesn't scroll past its edges (optional — small maps may not fill screen)
    this._camera.x = targetX;
    this._camera.y = targetY;

    if (this._tileContainer) {
      this._tileContainer.x = this._camera.x;
      this._tileContainer.y = this._camera.y;
    }
    if (this._fogTileContainer) {
      this._fogTileContainer.x = this._camera.x;
      this._fogTileContainer.y = this._camera.y;
    }
  }

  _onResize() {
    this._updateCamera();
    this._updateMinimap();
    this._repositionMinimap();
  }

  // ─── Game update loop ─────────────────────────────────────────────────────────

  _update(deltaMS) {
    const dt = deltaMS / 1000; // seconds

    // Pause movement while an encounter dialog is open
    if (this._encounterActive) return;

    const input = InputManager.getState(0);
    const mx = input.moveAxis.x;
    const my = input.moveAxis.y;

    let moved = false;
    let stepDist = 0;

    if (mx !== 0 || my !== 0) {
      // Normalize diagonal movement
      const len = Math.sqrt(mx * mx + my * my);
      const nx = mx / len;
      const ny = my / len;

      const stepX = nx * MOVE_SPEED * dt;
      const stepY = ny * MOVE_SPEED * dt;
      const newX = this._partyX + stepX;
      const newY = this._partyY + stepY;

      // Clamp and check passability
      const clampedX = Math.max(0, Math.min(LOCAL_MAP_W - 1, newX));
      const clampedY = Math.max(0, Math.min(LOCAL_MAP_H - 1, newY));

      const tileX = Math.floor(clampedX);
      const tileY = Math.floor(clampedY);
      const targetTile = this._tiles[tileY * LOCAL_MAP_W + tileX];

      if (targetTile && targetTile.passable) {
        stepDist = Math.sqrt(stepX * stepX + stepY * stepY);
        this._partyX = clampedX;
        this._partyY = clampedY;
        moved = true;
      }
    }

    if (moved) {
      const tx = Math.floor(this._partyX);
      const ty = Math.floor(this._partyY);

      WorldState.partyPosition.x = tx;
      WorldState.partyPosition.y = ty;

      if (window.__settings?.fogOfWar) {
        WorldState.revealAround(tx, ty, FOG_REVEAL_RADIUS);
      }
      this._fogDirty = true;

      EventBus.emit('local:partyMoved', { x: tx, y: ty });

      // ── Tile crossing detection ──────────────────────────────────────────
      // Only process time/encounter logic when the party crosses into a new tile
      const tileChanged = (tx !== this._prevTileX || ty !== this._prevTileY);

      if (tileChanged) {
        this._prevTileX = tx;
        this._prevTileY = ty;

        // Check for dungeon entry before encounter rolls
        const currentTile = this._tiles[ty * LOCAL_MAP_W + tx];
        if (currentTile?.type === 'dungeon') {
          this._promptDungeonEntry(currentTile);
          return;
        }

        // Advance in-game time by the cost of crossing this tile
        this._advanceTimeForTile(tx, ty);

        // Count tiles traveled toward the next encounter roll
        this._distanceSinceCheck += 1;
        if (this._encounterCooldown > 0) this._encounterCooldown -= 1;

        // Check for an encounter every 3 tiles traveled (when cooldown is clear)
        if (this._distanceSinceCheck >= 3 && this._encounterCooldown <= 0) {
          this._distanceSinceCheck = 0;
          this._checkForEncounter(tx, ty);
        }
      }
    }

    this._updatePartyPosition();
    this._updateCamera();

    if (this._fogDirty) {
      this._rebuildFogTiles();
      this._updateMinimap();
    }
  }

  // ─── Encounter integration ───────────────────────────────────────────────────

  /**
   * Ask EncounterSystem whether an encounter triggers at the current position.
   * Handles both 'combat' and 'dialog' encounter types.
   * Falls back gracefully when EncounterSystem is not loaded.
   *
   * @param {number} tx — Current tile X
   * @param {number} ty — Current tile Y
   */
  _checkForEncounter(tx, ty) {
    // EncounterSystem may be injected via window.__encounterSystem or imported
    const encounterSystem = window.__encounterSystem ?? null;
    if (!encounterSystem?.checkMovementEncounter) return;

    const region = WorldState.getRegion(this._regionId);
    const tile   = this._tiles[ty * LOCAL_MAP_W + tx];

    const context = {
      x:         tx,
      y:         ty,
      regionId:  this._regionId,
      biome:     region?.biome ?? 'plains',
      tileType:  tile?.type ?? 'grass',
      partyGold: WorldState.partyGold,
      isNight:   this._checkIsNight(),
    };

    let encounter = null;
    try {
      encounter = encounterSystem.checkMovementEncounter(context);
    } catch (e) {
      DebugLog.warn(`[encounter] checkMovementEncounter failed: ${e.message}`);
      return;
    }

    if (!encounter) return;

    DebugLog.event(
      `[encounter] Encounter triggered; type=${encounter.type} id=${encounter.id ?? 'unknown'} ` +
      `tile=${tx},${ty}`
    );

    // Impose a cooldown so the next check doesn't fire immediately after resolution
    this._encounterCooldown = 8;

    if (encounter.type === 'combat') {
      // Transition to combat scene
      const partyChars = window.__partyChars ?? [];
      const enemies    = encounter.enemies ?? [];
      SceneManager.transition('combat', { partyChars, enemies, sourceEncounter: encounter });
    } else {
      // Dialog/event encounter — show the dialog panel
      this._showEncounterDialog(encounter);
    }
  }

  /**
   * Open the EncounterDialog for a non-combat encounter.
   * @param {object} encounter
   */
  _showEncounterDialog(encounter) {
    this._encounterActive = true;

    const partyChars = window.__partyChars ?? [];

    EncounterDialog.show(encounter, partyChars, (result) => {
      this._encounterActive = false;

      if (result) {
        DebugLog.event(
          `[encounter] Dialog resolved; passed=${result.passed ?? false} ` +
          `success=${result.success ?? 'n/a'}`
        );

        // Apply any gold changes from the result
        if (result.goldDelta != null) {
          WorldState.partyGold = Math.max(0, (WorldState.partyGold ?? 0) + result.goldDelta);
          HUDPanel.update();
        }

        EventBus.emit('encounter:resolved', { encounter, result });
      }
    });
  }

  // ─── Dungeon entry prompt ─────────────────────────────────────────────────────

  /**
   * Show a confirmation prompt when the party steps onto a dungeon tile.
   * On Yes: transition to DungeonScene. On No: dismiss and resume movement.
   *
   * @param {object} tile — The dungeon tile
   */
  _promptDungeonEntry(tile) {
    // Don't stack prompts
    const stale = document.getElementById('dungeon-entry-prompt');
    if (stale) return;

    this._encounterActive = true;

    const dungeonType = tile.dungeonType ?? 'burial_mound';
    const dungeonName = tile.dungeonName ?? dungeonType.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());

    const seed = ((WorldState.world?.seed ?? 12345) ^ (tile.x * 0x7a3f + tile.y * 0x1b79)) >>> 0;
    const regionLevel = WorldState.currentRegionLevel ?? 1;

    const prompt = document.createElement('div');
    prompt.id = 'dungeon-entry-prompt';
    prompt.style.cssText = `
      position: fixed;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      background: rgba(8, 6, 4, 0.96);
      border: 1px solid #c8a020;
      border-radius: 5px;
      padding: 24px 32px;
      color: #ddccaa;
      font-family: Georgia, 'Times New Roman', serif;
      z-index: 350;
      text-align: center;
      min-width: 280px;
      max-width: min(420px, 90vw);
    `;
    prompt.innerHTML = `
      <div style="font-size: clamp(14px,1.5vw,18px); font-weight:bold; color:#c8a020; margin-bottom:10px;">
        ${dungeonName}
      </div>
      <div style="font-size: clamp(11px,1.1vw,13px); color:#9a8a6a; margin-bottom:16px;">
        A dungeon entrance lies before you.<br>Do you wish to enter?
      </div>
      <div style="display:flex; gap:10px; justify-content:center;">
        <button id="btn-dungeon-yes" style="
          background:#1a1208; border:1px solid #c8a020; color:#c8a020;
          padding:8px 24px; cursor:pointer; font-size:clamp(12px,1.2vw,14px);
          font-family:Georgia,serif; border-radius:3px;
        ">Enter</button>
        <button id="btn-dungeon-no" style="
          background:#1a1208; border:1px solid #5a4a2a; color:#aaa;
          padding:8px 24px; cursor:pointer; font-size:clamp(12px,1.2vw,14px);
          font-family:Georgia,serif; border-radius:3px;
        ">Leave</button>
      </div>
    `;

    document.body.appendChild(prompt);

    document.getElementById('btn-dungeon-yes')?.addEventListener('click', () => {
      prompt.remove();
      DebugLog.event(`[dungeon] Party entering dungeon; type=${dungeonType} seed=${seed}`);
      SceneManager.transition('dungeon', { dungeonType, regionLevel, seed });
    });

    document.getElementById('btn-dungeon-no')?.addEventListener('click', () => {
      prompt.remove();
      this._encounterActive = false;
      DebugLog.info('[dungeon] Party declined dungeon entry');
    });
  }

  // ─── Time integration ────────────────────────────────────────────────────────

  /**
   * Advance the in-game clock by the movement cost of the crossed tile.
   * Gracefully no-ops when TimeSystem is not loaded.
   *
   * @param {number} tx — Tile X
   * @param {number} ty — Tile Y
   */
  _advanceTimeForTile(tx, ty) {
    const timeSystem = window.__timeSystem ?? null;
    if (!timeSystem?.advanceTime) return;

    const tile = this._tiles[ty * LOCAL_MAP_W + tx];
    const terrain = tile?.type ?? 'grass';

    let cost = 1; // default: 1 minute per tile
    try {
      if (timeSystem.getMoveCost) {
        cost = timeSystem.getMoveCost(terrain);
      }
      timeSystem.advanceTime(cost);
    } catch (e) {
      DebugLog.warn(`[encounter] TimeSystem.advanceTime failed: ${e.message}`);
    }
  }

  /**
   * Check whether it is currently night via TimeSystem.
   * @returns {boolean}
   */
  _checkIsNight() {
    try {
      if (window.__timeSystem?.isNight) {
        return window.__timeSystem.isNight();
      }
    } catch (_) {}
    return false;
  }

  // ─── Minimap ─────────────────────────────────────────────────────────────────

  _buildMinimap() {
    const hudLayer = this._renderer.layers.hud;

    this._minimapContainer = new Container();
    this._minimapContainer.label = 'minimapContainer';
    hudLayer.addChild(this._minimapContainer);

    // Background
    const bg = new Graphics();
    bg.rect(0, 0, MINIMAP_W, MINIMAP_H);
    bg.fill({ color: 0x000000, alpha: 0.75 });
    bg.rect(0, 0, MINIMAP_W, MINIMAP_H);
    bg.stroke({ color: 0x5a4a2a, width: 1 });
    this._minimapContainer.addChild(bg);

    // Terrain layer
    this._minimapGfx = new Graphics();
    this._minimapContainer.addChild(this._minimapGfx);

    // Party dot (drawn on top)
    this._minimapPartyGfx = new Graphics();
    this._minimapContainer.addChild(this._minimapPartyGfx);

    this._repositionMinimap();
    this._updateMinimap();
  }

  _repositionMinimap() {
    if (!this._minimapContainer) return;
    const vw = this._renderer.width;
    const vh = this._renderer.height;
    this._minimapContainer.x = vw - MINIMAP_W - MINIMAP_MARGIN;
    this._minimapContainer.y = vh - MINIMAP_H - MINIMAP_MARGIN;
  }

  _updateMinimap() {
    if (!this._minimapGfx || !this._tiles) return;

    const scaleX = MINIMAP_W / LOCAL_MAP_W;
    const scaleY = MINIMAP_H / LOCAL_MAP_H;

    this._minimapGfx.clear();

    for (const tile of this._tiles) {
      const fogState = WorldState.getFogAt(this._regionId, tile.x, tile.y);
      const px = tile.x * scaleX;
      const py = tile.y * scaleY;
      const pw = Math.ceil(scaleX);
      const ph = Math.ceil(scaleY);

      if (fogState === 0) {
        // Completely unknown — draw as black
        this._minimapGfx.rect(px, py, pw, ph);
        this._minimapGfx.fill({ color: 0x000000 });
      } else {
        // Show tile color (semi or revealed)
        this._minimapGfx.rect(px, py, pw, ph);
        const alpha = fogState === 1 ? 0.5 : 1.0;
        this._minimapGfx.fill({ color: tile.color, alpha });
      }
    }

    // Party dot
    if (this._minimapPartyGfx) {
      this._minimapPartyGfx.clear();
      const dotX = Math.floor(this._partyX) * scaleX + scaleX / 2;
      const dotY = Math.floor(this._partyY) * scaleY + scaleY / 2;
      this._minimapPartyGfx.circle(dotX, dotY, 2.5);
      this._minimapPartyGfx.fill({ color: 0xffdd00 });
    }
  }

  // ─── Mobile D-pad ────────────────────────────────────────────────────────────

  _buildMobileDpad() {
    if (!('ontouchstart' in window) && !navigator.maxTouchPoints) return;

    // Remove any stale d-pad from a previous visit
    const stale = document.getElementById('local-map-dpad');
    if (stale) stale.remove();

    const dpad = document.createElement('div');
    dpad.id = 'local-map-dpad';
    dpad.style.cssText = `
      position: fixed;
      bottom: 20px;
      left: 20px;
      width: 120px;
      height: 120px;
      z-index: 200;
      pointer-events: auto;
      opacity: 0.75;
      user-select: none;
    `;

    const dirs = [
      { id: 'up',    label: '▲', top: '0',    left: '40px', dx: 0,  dy: -1 },
      { id: 'down',  label: '▼', top: '80px', left: '40px', dx: 0,  dy: 1  },
      { id: 'left',  label: '◀', top: '40px', left: '0',    dx: -1, dy: 0  },
      { id: 'right', label: '▶', top: '40px', left: '80px', dx: 1,  dy: 0  },
    ];

    for (const dir of dirs) {
      const btn = document.createElement('button');
      btn.textContent = dir.label;
      btn.style.cssText = `
        position: absolute;
        top: ${dir.top};
        left: ${dir.left};
        width: 40px;
        height: 40px;
        background: rgba(20, 15, 8, 0.85);
        border: 1px solid #5a4a2a;
        color: #ddccaa;
        font-size: 16px;
        border-radius: 4px;
        cursor: pointer;
        touch-action: none;
        display: flex;
        align-items: center;
        justify-content: center;
      `;

      btn.addEventListener('pointerdown', (e) => {
        e.preventDefault();
        import('../input/InputManager.js').then(m => {
          m.default._states[0].moveAxis.x = dir.dx;
          m.default._states[0].moveAxis.y = dir.dy;
        });
      });
      btn.addEventListener('pointerup', () => {
        import('../input/InputManager.js').then(m => {
          m.default._states[0].moveAxis.x = 0;
          m.default._states[0].moveAxis.y = 0;
        });
      });
      btn.addEventListener('pointerleave', () => {
        import('../input/InputManager.js').then(m => {
          m.default._states[0].moveAxis.x = 0;
          m.default._states[0].moveAxis.y = 0;
        });
      });

      dpad.appendChild(btn);
    }

    document.body.appendChild(dpad);
    this._dpadEl = dpad;
  }

  // ─── HTML Panel ──────────────────────────────────────────────────────────────

  _buildHTMLPanel() {
    const existing = document.getElementById('panel-local-map-hud');
    if (existing) existing.remove();

    const panel = document.createElement('div');
    panel.id = 'panel-local-map-hud';
    panel.style.cssText = `
      position: fixed;
      top: 12px;
      right: 12px;
      background: rgba(12, 8, 4, 0.80);
      border: 1px solid #5a4a2a;
      border-radius: 4px;
      padding: 8px 12px;
      color: #ddccaa;
      font-family: serif;
      font-size: 12px;
      z-index: 100;
      pointer-events: auto;
      min-width: 160px;
      text-align: right;
    `;

    const world = WorldState.world;
    const region = world?.regions.find(r => r.id === this._regionId);

    panel.innerHTML = `
      <div style="font-size:13px; font-weight:bold; color:#e8d8a0; margin-bottom:3px;">
        ${region?.name ?? 'Unknown'}
      </div>
      <div style="font-size:11px; color:#9a8a6a; margin-bottom:6px;">
        Level ${region?.level ?? '?'} &nbsp;|&nbsp; ${(region?.biome ?? 'unknown').replace('_', ' ')}
      </div>
      <div id="local-hud-time" style="font-size:10px; color:#7a6a4a; margin-bottom:6px;">Time: Dawn</div>
      <button id="btn-local-world-map" style="
        background:#1a1208; border:1px solid #5a4a2a; color:#aaa;
        padding:4px 8px; cursor:pointer; font-size:11px; font-family:serif;
        border-radius:3px; width:100%;
      ">World Map</button>
    `;

    document.body.appendChild(panel);
    this._panel = panel;

    document.getElementById('btn-local-world-map')?.addEventListener('click', () => {
      SceneManager.transition('worldMap');
    });
  }

  _removeHTMLPanel() {
    if (this._panel) {
      this._panel.remove();
      this._panel = null;
    }
  }

  // ─── Onboarding hint ─────────────────────────────────────────────────────────

  /**
   * Show a brief control-hint overlay at the bottom-center of the screen.
   * Fades out after 5 seconds or immediately on any keypress.
   * Stored as this._hintEl so destroy() can clean it up if needed.
   */
  _showOnboardingHint() {
    // Remove any leftover hint from a previous visit
    const stale = document.getElementById('local-map-onboarding-hint');
    if (stale) stale.remove();

    const hint = document.createElement('div');
    hint.id = 'local-map-onboarding-hint';
    hint.style.cssText = `
      position: fixed;
      bottom: clamp(24px, 5vh, 48px);
      left: 50%;
      transform: translateX(-50%);
      background: rgba(10, 8, 8, 0.88);
      border: 1px solid #c8a020;
      border-radius: 5px;
      padding: 14px 28px;
      text-align: center;
      font-family: Georgia, 'Times New Roman', serif;
      pointer-events: none;
      z-index: 200;
      opacity: 1;
      transition: opacity 0.5s ease;
      min-width: 280px;
      max-width: min(420px, 90vw);
    `;

    hint.innerHTML = `
      <div style="
        font-size: clamp(15px, 1.6vw, 18px);
        font-weight: bold;
        color: #c8a020;
        letter-spacing: 0.06em;
        text-transform: uppercase;
        margin-bottom: 10px;
      ">Adventure begins!</div>
      <div style="
        font-size: clamp(11px, 1.2vw, 13px);
        color: #e8d5b0;
        line-height: 1.8;
      ">
        WASD / Arrow Keys &mdash; Move party<br>
        Enter towns to rest and trade<br>
        <span style="color: #a09070; font-size: 0.92em;">Press any key to dismiss</span>
      </div>
    `;

    document.body.appendChild(hint);
    this._hintEl = hint;

    // Auto-dismiss after 5 seconds
    this._hintTimer = setTimeout(() => this._dismissHint(), 5000);

    // Dismiss on any keypress
    this._hintKeyListener = () => this._dismissHint();
    window.addEventListener('keydown', this._hintKeyListener);
  }

  /**
   * Fade out and remove the onboarding hint, cleaning up listeners and timers.
   */
  _dismissHint() {
    if (!this._hintEl) return;

    if (this._hintTimer) {
      clearTimeout(this._hintTimer);
      this._hintTimer = null;
    }
    if (this._hintKeyListener) {
      window.removeEventListener('keydown', this._hintKeyListener);
      this._hintKeyListener = null;
    }

    const el = this._hintEl;
    this._hintEl = null;

    el.style.opacity = '0';
    setTimeout(() => { if (el.parentNode) el.remove(); }, 500);
  }

  // ─── Lifecycle ───────────────────────────────────────────────────────────────

  async destroy() {
    // Remove ticker
    if (this._ticker && this._renderer?.app?.ticker) {
      this._renderer.app.ticker.remove(this._ticker);
      this._ticker = null;
    }

    // Remove PixiJS objects
    if (this._tileContainer) {
      this._renderer.layers.world.removeChild(this._tileContainer);
      this._tileContainer.destroy({ children: true });
      this._tileContainer = null;
    }

    if (this._fogTileContainer) {
      this._renderer.layers.world.removeChild(this._fogTileContainer);
      this._fogTileContainer.destroy({ children: true });
      this._fogTileContainer = null;
    }

    if (this._partyContainer) {
      this._renderer.layers.entities.removeChild(this._partyContainer);
      this._partyContainer.destroy({ children: true });
      this._partyContainer = null;
    }

    if (this._minimapContainer) {
      this._renderer.layers.hud.removeChild(this._minimapContainer);
      this._minimapContainer.destroy({ children: true });
      this._minimapContainer = null;
    }

    this._removeHTMLPanel();

    // Remove mobile d-pad if present
    if (this._dpadEl) { this._dpadEl.remove(); this._dpadEl = null; }

    // Remove onboarding hint if still present
    if (this._hintEl) { this._hintEl.remove(); this._hintEl = null; }
    if (this._hintTimer) { clearTimeout(this._hintTimer); this._hintTimer = null; }
    if (this._hintKeyListener) {
      window.removeEventListener('keydown', this._hintKeyListener);
      this._hintKeyListener = null;
    }

    // Destroy HUD overlay
    HUDPanel.destroy();

    // Hide any open encounter dialog
    if (EncounterDialog.isVisible()) {
      EncounterDialog.hide();
    }

    // Remove dungeon entry prompt if visible
    const dungeonPrompt = document.getElementById('dungeon-entry-prompt');
    if (dungeonPrompt) dungeonPrompt.remove();

    // Unsubscribe event bus
    if (this._resizeUnsub) { this._resizeUnsub(); this._resizeUnsub = null; }
    if (this._fogUpdateUnsub) { this._fogUpdateUnsub(); this._fogUpdateUnsub = null; }

    DebugLog.info('[world] LocalMapScene destroyed');
  }
}
